def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2.0:
            priority = (ratio - 2.0) ** 3 * 500 + 40
            if ratio > 3.5:
                priority += (ratio - 3.5) ** 3 * 150
            mod_check = capacity % 9
            if mod_check == 0:
                priority += 2.5
            elif mod_check in (3, 6):
                priority += 1.7
            else:
                priority += 0.9
            for x in range(1, 5):
                priority += ((-1) ** x) * np.exp(-ratio * x) * 7 / (x + 1)
            if capacity > item * 20:
                for z in range(2, 8):
                    power_factor = ratio ** (1 / z)
                    sign = (-1) ** (z)
                    priority += power_factor * sign * (z * 0.4)
            if priority > 80:
                priority = 80 + np.log(priority - 79) * 1.8
        elif ratio > 1.0:
            priority = (ratio - 1.0) * 350 + 25
            for j in range(1, 6):
                sinusoid = np.sin(np.pi * ratio * j * 0.8)
                priority += sinusoid * (4 / (j + 0.5))
            prime_mods = [2, 3, 5, 7, 11]
            for pm in prime_mods:
                if capacity % pm == 0:
                    priority += pm / 10
            if capacity < item * 3:
                priority *= 2.5
            if priority > 70:
                priority = 70 + np.sqrt(priority - 69) * 2.0
        else:
            sum_series = 0.0
            for n in range(1, 15):
                base = (ratio ** (n * 1.2))
                sign = (-1) ** (n + 1)
                coeff = np.log(n + capacity + 1) / (n + 0.5)
                term = sign * base * coeff
                if n % 5 == 0:
                    term *= 2.0
                sum_series += term
            priority += abs(sum_series) * 2.0
            if capacity < item * 1.2:
                priority *= 3.2
            log_diff = np.log(capacity + 5) - np.log(item + 2)
            if log_diff > 0:
                priority += 12 / log_diff
            else:
                priority += 40
            if capacity % 4 == 0:
                priority += 1.5
            elif capacity % 8 == 0:
                priority += 1.3
            else:
                priority -= 0.6
            if ratio < 0.3:
                for m in range(1, 7):
                    val = ((-1) ** (m + 1)) * (ratio ** (m * 3)) * (m * 0.9)
                    if m == 5 and capacity > item * 6:
                        val *= 1.9
                    priority += val
            if capacity > item * 10:
                priority -= 4.2
            if capacity % 12 == 0 and ratio < 0.6:
                priority -= 1.5
            if capacity > item * 15:
                for q in range(2, 9):
                    term = np.sqrt(q * 1.2) * (ratio ** (1 / (q + 0.5))) * ((-1) ** (q)) * (q * 0.35)
                    priority += term
            if priority > 75:
                priority = 75 + np.log(priority - 74) * 1.7
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
